INSERT INTO `certificates` VALUES (1,1,'<!DOCTYPE html>\r\n<html lang=\"en\">\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <title>Academic Clearance Certificate</title>\r\n    <style>\r\n        body {\r\n            font-family: \'Georgia\', serif;\r\n            margin: 0;\r\n            padding: 20px;\r\n            background: #f5f5f5;\r\n        }\r\n        .certificate {\r\n            width: 210mm;\r\n            height: 297mm;\r\n            margin: 0 auto;\r\n            padding: 40px;\r\n            background: #fff;\r\n            box-shadow: 0 0 20px rgba(0,0,0,0.1);\r\n            border: 2px solid #1a5490;\r\n            border-radius: 10px;\r\n            position: relative;\r\n        }\r\n        .header {\r\n            text-align: center;\r\n            border-bottom: 2px solid #1a5490;\r\n            padding-bottom: 20px;\r\n            margin-bottom: 40px;\r\n        }\r\n        .logo {\r\n            font-size: 14px;\r\n            color: #1a5490;\r\n            font-weight: bold;\r\n            margin-bottom: 10px;\r\n        }\r\n        .title {\r\n            font-size: 36px;\r\n            color: #1a5490;\r\n            font-weight: bold;\r\n            margin: 20px 0;\r\n        }\r\n        .subtitle {\r\n            font-size: 18px;\r\n            color: #666;\r\n            margin: 10px 0;\r\n        }\r\n        .content {\r\n            margin: 40px 0;\r\n            line-height: 1.8;\r\n            text-align: center;\r\n        }\r\n        .certificate-text {\r\n            font-size: 16px;\r\n            color: #333;\r\n            margin: 30px 0;\r\n        }\r\n        .student-info {\r\n            background: #f9f9f9;\r\n            padding: 20px;\r\n            border-radius: 5px;\r\n            margin: 30px 0;\r\n            text-align: left;\r\n        }\r\n        .info-row {\r\n            display: flex;\r\n            margin: 10px 0;